const canvas=document.getElementById('game');const ctx=canvas.getContext('2d');const statusEl=document.getElementById('status');const startBtn=document.getElementById('start');let running=false;let x=24;let y=160;let vx=2;let score=0;function draw(){ctx.clearRect(0,0,canvas.width,canvas.height);ctx.fillStyle='#38bdf8';ctx.fillRect(x,y,24,24);ctx.fillStyle='#f59e0b';for(let i=0;i<5;i+=1){ctx.fillRect(60+i*72,40+i*18,18,18);}ctx.fillStyle='#f8fafc';ctx.fillText('Score: '+score,12,20);}function tick(){if(!running)return;x+=vx;if(x>canvas.width){x=-24;score+=1;statusEl.textContent='Loop cleared '+score+' times.';}draw();requestAnimationFrame(tick);}startBtn.addEventListener('click',()=>{if(running)return;running=true;statusEl.textContent='Running';tick();});draw();